// $input.first() = Supabase REST response (array of windows rows)
const windowRows = $input.first().json;
const window = Array.isArray(windowRows) ? windowRows[0] : windowRows;

if (!window || !window.email) {
  throw new Error('Window owner not found — window_id mungkin tidak valid');
}

// Ambil data peer dari node Webhook (node index 0)
const webhookData = $('Webhook').first().json;
const peerRecord  = webhookData.body?.record ?? webhookData.record ?? {};
const peerName    = peerRecord.peer_name ?? 'Seseorang';

const name      = window.name;
const email     = window.email;
const code      = window.code;
const siteUrl   = 'https://YOUR_SITE.netlify.app'; // ← ganti dengan URL Netlify kamu
const resultLink = `${siteUrl}/test/result`;
const peerLink   = `${siteUrl}/peer/${code}`;

const displayPeer = peerName !== 'Seseorang' ? `<strong>${peerName}</strong>` : 'Seseorang';

const htmlContent = `
<!DOCTYPE html>
<html lang="id">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <style>
    body { font-family: 'Segoe UI', Arial, sans-serif; color: #1a1a2e; background: #f8f8f8; margin: 0; padding: 0; }
    .wrapper { max-width: 600px; margin: 0 auto; background: #ffffff; }
    .header { background: linear-gradient(135deg, #f59e0b 0%, #ef4444 100%); padding: 40px 32px; text-align: center; }
    .header h1 { color: #ffffff; font-size: 26px; margin: 0; font-weight: 700; }
    .header p  { color: rgba(255,255,255,0.85); margin: 8px 0 0; font-size: 14px; }
    .body  { padding: 32px; }
    .body p { line-height: 1.7; color: #333; font-size: 15px; margin: 0 0 16px; }
    .highlight { background: #fff7ed; border-left: 4px solid #f59e0b; border-radius: 4px; padding: 16px 20px; margin: 20px 0; font-size: 15px; color: #92400e; }
    .btn { display: inline-block; background: #4f46e5; color: #ffffff !important; padding: 14px 28px; border-radius: 30px; text-decoration: none; font-weight: 600; font-size: 15px; margin: 8px 0; }
    .btn-ghost { background: transparent; color: #6366f1 !important; border: 2px solid #6366f1; }
    .divider { border: none; border-top: 1px solid #eee; margin: 28px 0; }
    .link-text { color: #6366f1; font-size: 13px; word-break: break-all; }
    .footer { background: #fff7ed; padding: 24px 32px; text-align: center; }
    .footer p { color: #9ca3af; font-size: 12px; margin: 0; }
  </style>
</head>
<body>
  <div class="wrapper">
    <div class="header">
      <h1>👀 Ada feedback baru masuk!</h1>
      <p>Seseorang baru saja mengisi Johari Window milikmu</p>
    </div>
    <div class="body">
      <p>Hai <strong>${name}</strong>,</p>

      <div class="highlight">
        ${displayPeer} baru saja mengisi perspektif mereka tentangmu di Johari Window-mu.
      </div>

      <p>Setiap feedback yang masuk memperkaya gambar dirimu — semakin banyak peer yang mengisi, semakin akurat dan lengkap Johari Window-mu.</p>

      <div style="text-align:center; margin: 28px 0">
        <a href="${resultLink}" class="btn">Lihat Johari Window-ku →</a>
      </div>

      <hr class="divider">

      <p>Belum cukup peer yang mengisi? Bagikan lagi ke orang lain:</p>
      <p class="link-text">${peerLink}</p>

      <div style="text-align:center; margin: 20px 0">
        <a href="${peerLink}" class="btn btn-ghost">Salin link peer →</a>
      </div>

      <p style="font-size:13px; color:#888">Idealnya minimal 3–5 orang peer untuk hasil yang kaya dan akurat.</p>
    </div>
    <div class="footer">
      <p>Email ini dikirim otomatis dari <strong>Johari Window ID</strong>.<br>Kamu menerima email ini karena kamu membuat Johari Window dengan kode <strong>${code}</strong>.</p>
    </div>
  </div>
</body>
</html>
`;

return [{
  json: {
    sender: {
      name: 'Johari Window ID',
      email: 'noreply@YOUR_DOMAIN.com'  // ← ganti dengan email sender terverifikasi di Brevo
    },
    to: [{ email, name }],
    subject: `👀 Ada peer baru yang mengisi Johari Window-mu, ${name}!`,
    htmlContent
  }
}];
